 1	import React from 'react';
 2	import { TraceQueryPanelWrapper } from '../../components/PersesWrapper';
 3	import { TraceTable as PersesTraceTable } from '@perses-dev/panels-plugin';
 4	import {
 5	  Button,
 6	  EmptyState,
 7	  EmptyStateActions,
 8	  EmptyStateBody,
 9	  EmptyStateFooter,
10	  EmptyStateHeader,
11	  EmptyStateIcon,
12	} from '@patternfly/react-core';
13	import { SearchIcon } from '@patternfly/react-icons';
14	import { useTranslation } from 'react-i18next';
15	import { linkToTraceDetailPage } from '../../links';
16	import './TraceTable.css';
17	import { TempoTraceQuerySpec } from '@perses-dev/tempo-plugin';
18	
19	interface TraceTableProps {
20	  runQuery: (spec: TempoTraceQuerySpec) => void;
21	}
22	
23	export function TraceTable({ runQuery }: TraceTableProps) {
24	  const { t } = useTranslation('plugin__distributed-tracing-console-plugin');
25	
26	  const noResults = (
27	    <EmptyState>
28	      <EmptyStateHeader
29	        titleText={t('No results found')}
30	        headingLevel="h4"
31	        icon={<EmptyStateIcon icon={SearchIcon} />}
32	      />
33	      <EmptyStateBody>
34	        {t('No results match this query criteria. Clear all filters and try again.')}
35	      </EmptyStateBody>
36	      <EmptyStateFooter>
37	        <EmptyStateActions>
38	          <Button variant="link" onClick={() => runQuery({ query: '{}' })}>
39	            {t('Clear all filters')}
40	          </Button>
41	        </EmptyStateActions>
42	      </EmptyStateFooter>
43	    </EmptyState>
44	  );
45	
46	  return (
47	    <TraceQueryPanelWrapper noResults={noResults}>
48	      <div className="dt-plugin-trace-table">
49	        <PersesTraceTable.PanelComponent
50	          spec={{ visual: { palette: { mode: 'categorical' } } }}
51	          traceLink={traceDetailLink}
52	        />
53	      </div>
54	    </TraceQueryPanelWrapper>
55	  );
56	}
57	
58	export function traceDetailLink({ traceId }: { traceId: string }) {
59	  return linkToTraceDetailPage(traceId);
60	}

